### Combine List Schedules and Availability Settings Atoms - JavaScript

Source: https://github.com/calcom/cal.com/blob/main/docs/platform/atoms/list-schedules.mdx

This example shows how to integrate the ListSchedules atom with the AvailabilitySettings atom. It involves creating two pages: one to list schedules and redirect to an edit page, and another dynamic route to display and manage individual schedule settings based on the `scheduleId`.

```javascript
import { ListSchedules } from "@calcom/atoms";

export default function ListSchedules() {
  return (
    <>
      <ListSchedules getRedirectUrl={(scheduleId) => `/availability/${scheduleId}`} />
    </>
  );
}
```

```javascript
import { AvailabilitySettings } from "@calcom/atoms";
import { useRouter } from "next/router";

export default function Availability() {
  const router = useRouter();

  return (
    <>
       <AvailabilitySettings
          id={router.query.scheduleId as string}
          onUpdateSuccess={() => {
            console.log("Updated schedule successfully");
          }}
       />
    </>
  )
}
```

